1	package com.toolbox.ui;
2	
3	import com.toolbox.plugin.PluginLoader;
4	import com.toolbox.plugin.PluginRegistry;
5	import com.toolbox.ui.content.ContentArea;
6	import com.toolbox.ui.sidebar.Sidebar;
7	import com.toolbox.ui.titlebar.TitleBar;
8	import javafx.animation.*;
9	import javafx.geometry.Insets;
10	import javafx.geometry.Pos;
11	import javafx.scene.control.Label;
12	import javafx.scene.layout.*;
13	import javafx.scene.paint.*;
14	import javafx.scene.shape.*;
15	import javafx.stage.Stage;
16	import javafx.util.Duration;
17	
18	import java.time.LocalTime;
19	import java.time.format.DateTimeFormatter;
20	
21	/**
22	 * 主窗口根节点。
23	 * 负责组装 TitleBar / Sidebar / ContentArea / StatusBar，
24	 * 并持有 PluginLoader 和 PluginRegistry 的生命周期。
25	 */
26	public class MainWindow extends StackPane {
27	
28	    private final Stage        stage;
29	    private final PluginLoader loader;
30	    private final PluginRegistry registry;
31	
32	    private final TitleBar    titleBar;
33	    private final Sidebar     sidebar;
34	    private final ContentArea contentArea;
35	
36	    // 状态栏标签
37	    private final Label statusToolCount    = statusText("0 个工具");
38	    private final Label statusPluginCount  = statusText("0 个插件");
39	    private final Label clockLabel         = statusText("");
40	
41	    private Timeline clockTimeline;
42	
43	    public MainWindow(Stage stage, PluginLoader loader, PluginRegistry registry) {
44	        this.stage    = stage;
45	        this.loader   = loader;
46	        this.registry = registry;
47	
48	        titleBar    = new TitleBar(stage, this::openSettings);
49	        sidebar     = new Sidebar();
50	        contentArea = new ContentArea();
51	
52	        buildScene();
53	        wireEvents();
54	        startClock();
55	        playEntryAnimation();
56	    }
57	
58	    // ── 构建场景树 ────────────────────────────────────────
59	
60	    private void buildScene() {
61	        // 背景光晕层（放在最底层）
62	        Pane orbLayer = buildOrbLayer();
63	
64	        // 主窗口玻璃面板
65	        BorderPane windowPane = new BorderPane();
66	        windowPane.getStyleClass().add("app-root");
67	        windowPane.setStyle(
68	            "-fx-background-color: rgba(13,14,17,0.72);" +
69	            "-fx-background-radius: 20;" +
70	            "-fx-border-radius: 20;" +
71	            "-fx-border-color: rgba(255,255,255,0.10);" +
72	            "-fx-border-width: 1;" +
73	            "-fx-effect: dropshadow(gaussian, rgba(0,0,0,0.6), 60, 0, 0, 20);"
74	        );
75	
76	        // 标题栏
77	        windowPane.setTop(titleBar);
78	
79	        // 中间：侧边栏 + 内容区
80	        HBox body = new HBox(sidebar, contentArea);
81	        HBox.setHgrow(contentArea, Priority.ALWAYS);
82	        windowPane.setCenter(body);
83	
84	        // 状态栏
85	        windowPane.setBottom(buildStatusBar());
86	
87	        // 顶部高光描边（模拟玻璃厚度）
88	        Rectangle topHighlight = new Rectangle();
89	        topHighlight.setMouseTransparent(true);
90	        topHighlight.setStyle(
91	            "-fx-fill: transparent;" +
92	            "-fx-stroke: rgba(255,255,255,0.12);" +
93	            "-fx-stroke-width: 1;" +
94	            "-fx-arc-width: 40; -fx-arc-height: 40;"
95	        );
96	        topHighlight.widthProperty().bind(widthProperty());
97	        topHighlight.heightProperty().bind(heightProperty());
98	
99	        getChildren().addAll(orbLayer, windowPane, topHighlight);
100	        setAlignment(windowPane, Pos.CENTER);
101	        setAlignment(topHighlight, Pos.CENTER);
102	    }
103	
104	    // ── 背景光晕 ──────────────────────────────────────────
105	
106	    private Pane buildOrbLayer() {
107	        Pane layer = new Pane();
108	        layer.setMouseTransparent(true);
109	        layer.setStyle("-fx-background-color: #0d0e11;");
110	
111	        // 三个彩色高斯模糊光球
112	        layer.getChildren().addAll(
113	            orb(480, "#3b5bdb", -80, -120, 0),
114	            orb(360, "#7048e8",  -60, 200,  -6000),
115	            orb(300, "#1c7ed6",  300, 400, -12000)
116	        );
117	        return layer;
118	    }
119	
120	    private StackPane orb(double size, String color, double x, double y, double animDelay) {
121	        Circle c = new Circle(size / 2,
122	            Color.web(color, 0.28));
123	        c.setEffect(new javafx.scene.effect.GaussianBlur(60));
124	
125	        StackPane wrap = new StackPane(c);
126	        wrap.setTranslateX(x);
127	        wrap.setTranslateY(y);
128	        wrap.setMouseTransparent(true);
129	
130	        // 漂浮动画
131	        TranslateTransition drift = new TranslateTransition(Duration.millis(18000), wrap);
132	        drift.setByX(30); drift.setByY(20);
133	        drift.setAutoReverse(true);
134	        drift.setCycleCount(Animation.INDEFINITE);
135	        drift.setDelay(Duration.millis(Math.abs(animDelay)));
136	        drift.setInterpolator(Interpolator.EASE_BOTH);
137	        drift.play();
138	
139	        ScaleTransition breathe = new ScaleTransition(Duration.millis(12000), wrap);
140	        breathe.setFromX(1.0); breathe.setFromY(1.0);
141	        breathe.setToX(1.08);  breathe.setToY(1.08);
142	        breathe.setAutoReverse(true);
143	        breathe.setCycleCount(Animation.INDEFINITE);
144	        breathe.setInterpolator(Interpolator.EASE_BOTH);
145	        breathe.play();
146	
147	        return wrap;
148	    }
149	
150	    // ── 状态栏 ────────────────────────────────────────────
151	
152	    private HBox buildStatusBar() {
153	        // 活动指示点
154	        Circle dot = new Circle(3, Color.web("#4cd97b"));
155	        dot.setEffect(new javafx.scene.effect.Glow(0.8));
156	        FadeTransition pulse = new FadeTransition(Duration.millis(2500), dot);
157	        pulse.setFromValue(1.0); pulse.setToValue(0.4);
158	        pulse.setAutoReverse(true); pulse.setCycleCount(Animation.INDEFINITE);
159	        pulse.play();
160	
161	        Label sep = statusText("·");
162	        sep.setStyle("-fx-text-fill: rgba(255,255,255,0.15); -fx-font-size: 11px;");
163	
164	        Region spacer = new Region();
165	        HBox.setHgrow(spacer, Priority.ALWAYS);
166	
167	        HBox bar = new HBox(10);
168	        bar.getStyleClass().add("statusbar");
169	        bar.setAlignment(Pos.CENTER_LEFT);
170	        bar.setPadding(new Insets(0, 16, 0, 16));
171	        bar.getChildren().addAll(dot, statusToolCount, sep, statusPluginCount, spacer, clockLabel);
172	        return bar;
173	    }
174	
175	    private Label statusText(String text) {
176	        Label l = new Label(text);
177	        l.getStyleClass().add("status-text");
178	        return l;
179	    }
180	
181	    // ── 事件连接 ──────────────────────────────────────────
182	
183	    private void wireEvents() {
184	        // 绑定插件列表到内容区
185	        contentArea.setPlugins(registry.getPlugins());
186	
187	        // 侧边栏分类切换 → 内容区过滤
188	        sidebar.setOnCategorySelect(categoryId -> {
189	            if ("settings".equals(categoryId)) { openSettings(); return; }
190	            contentArea.showCategory(categoryId);
191	        });
192	
193	        // 插件列表变化 → 更新状态栏
194	        registry.getPlugins().addListener(
195	            (javafx.collections.ListChangeListener<com.toolbox.api.ToolPlugin>) c -> {
196	                int total   = registry.getPlugins().size();
197	                int plugins = (int) registry.getPlugins().stream()
198	                    .filter(p -> !"builtin".equals(p.getType())).count();
199	                statusToolCount.setText(total + " 个工具");
200	                statusPluginCount.setText(plugins + " 个插件");
201	                sidebar.updateBadge("plugins", plugins);
202	            }
203	        );
204	
205	        // 工具启动回调
206	        contentArea.setOnLaunch(plugin -> {
207	            registry.activate(plugin);
208	            contentArea.showPage(plugin.createView(), plugin.getName());
209	        });
210	    }
211	
212	    // ── 设置页面 ──────────────────────────────────────────
213	
214	    private void openSettings() {
215	        Label placeholder = new Label("⚙️  设置面板\n（即将实现）");
216	        placeholder.setStyle(
217	            "-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 16px;" +
218	            "-fx-alignment: center; -fx-text-alignment: center;"
219	        );
220	        StackPane page = new StackPane(placeholder);
221	        page.setStyle("-fx-background-color: transparent;");
222	        contentArea.showPage(page, "设置");
223	    }
224	
225	    // ── 入场动画 ──────────────────────────────────────────
226	
227	    private void playEntryAnimation() {
228	        // 找到 windowPane（第二个子节点）
229	        javafx.scene.Node windowPane = getChildren().get(1);
230	        windowPane.setOpacity(0);
231	        windowPane.setScaleX(0.94);
232	        windowPane.setScaleY(0.94);
233	        windowPane.setTranslateY(16);
234	
235	        FadeTransition ft = new FadeTransition(Duration.millis(500), windowPane);
236	        ft.setToValue(1);
237	
238	        ScaleTransition st = new ScaleTransition(Duration.millis(500), windowPane);
239	        st.setToX(1); st.setToY(1);
240	        st.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
241	
242	        TranslateTransition tt = new TranslateTransition(Duration.millis(500), windowPane);
243	        tt.setToY(0);
244	        tt.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
245	
246	        new ParallelTransition(ft, st, tt).play();
247	    }
248	
249	    // ── 时钟 ──────────────────────────────────────────────
250	
251	    private void startClock() {
252	        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("HH:mm:ss");
253	        clockTimeline = new Timeline(new KeyFrame(Duration.seconds(1), e ->
254	            clockLabel.setText(LocalTime.now().format(fmt))
255	        ));
256	        clockTimeline.setCycleCount(Animation.INDEFINITE);
257	        clockTimeline.play();
258	        clockLabel.setText(LocalTime.now().format(fmt)); // 立即显示
259	    }
260	
261	    /** 应用退出时调用，清理资源 */
262	    public void shutdown() {
263	        if (clockTimeline != null) clockTimeline.stop();
264	        loader.stop();
265	    }
266	}
